#include <iostream>
#include <string>

int main() {
    int n;
    std::cin >> n;

    std::string season;

    // February (2) is spring, so:
    // Spring:  2, 3, 4
    // Summer:  5, 6, 7
    // Autumn:  8, 9, 10
    // Winter:  11, 12, 1
    if (n == 2 || n == 3 || n == 4) {
        season = "Spring";
    } else if (n == 5 || n == 6 || n == 7) {
        season = "Summer";
    } else if (n == 8 || n == 9 || n == 10) {
        season = "Autumn";
    } else { // 11, 12, 1
        season = "Winter";
    }

    std::cout << season << std::endl;

    return 0;
}
